def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = 0 if item == 0 and capacity == 0 else np.inf
            continue
        ratio = item / capacity
        if ratio < 0:
            priorities[i] = np.inf
            continue
        if item == 0:
            priorities[i] = 0
            continue
        priority_score = 0.0
        factor = 1.0
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 3:
            penalty = 0.0
            for n in range(1, 7):
                penalty += (ratio ** (3 * n)) / (n ** 3 + 2)
            priority_score = (ratio ** 5) / 4 + penalty
            factor = sum([((-1) ** k) / (k + 1) for k in range(5)])
            priorities[i] = priority_score * factor * 3
        elif 2 < ratio <= 3:
            base = 0.0
            for a in range(1, 5):
                term = ((-1) ** (a + 1)) * (ratio ** a) / (a * a + 1)
                base += term
            decay = 1.0
            for b in range(1, 6):
                decay *= (b + 2) / (b + ratio + 2)
            priorities[i] = abs(base) * decay * 12
        elif 1 < ratio <= 2:
            intermediate = 0
            for c in range(1, 10):
                if c % 2 == 0:
                    intermediate += (ratio ** c) / (c * 3)
                else:
                    intermediate -= (ratio ** c) / (c * 4)
            multiplier = 18 if ratio < 1.5 else 10
            priorities[i] = abs(intermediate) * multiplier
        elif 0 < ratio <= 1:
            temp = 0
            for d in range(1, 12):
                if d % 4 == 0:
                    temp += (ratio ** d) / (d + 1)
                elif d % 3 == 0:
                    temp -= (ratio ** d) / (d * 2)
                else:
                    temp += (ratio ** d) / (d * 3)
            mult = 25 if ratio < 0.1 else 20 if ratio < 0.3 else 15 if ratio < 0.6 else 7
            base_val = abs(temp) * mult
            if ratio > 0.85:
                extra_val = 0
                for e in range(1, 7):
                    extra_val += (ratio ** (2 * e)) / (e + 3)
                base_val += extra_val * 2
            priorities[i] = base_val
        else:
            priorities[i] = np.inf
    return priorities
